module top_module(
  input clk,
  input rst,
  input [n-1:0] din,
  output [n-1:0] dout
);parameter n = 8; // width of data input and output signals

reg [n-1:0] invalid_data;

always @(posedge clk) begin
  if (!rst) begin
    invalid_data <= 0;
  end else begin
    invalid_data <= din;
  end
end

assign dout = invalid_data;

endmodule
